import{_ as e,o as a,c as t,ag as i}from"./chunks/framework.DXGyWiRo.js";const c=JSON.parse('{"title":"Install K3s","description":"Notes on Install K3s.","frontmatter":{"title":"Install K3s","description":"Notes on Install K3s."},"headers":[],"relativePath":"misc/tutorials/setting-up-k3s-in-lxc-containers-using-netmaker/install-k3s/README.md","filePath":"misc/tutorials/setting-up-k3s-in-lxc-containers-using-netmaker/install-k3s/README.md"}'),n={name:"misc/tutorials/setting-up-k3s-in-lxc-containers-using-netmaker/install-k3s/README.md"};function r(l,s,o,h,p,k){return a(),t("div",null,[...s[0]||(s[0]=[i(`<h1 id="install-k3s" tabindex="-1">Install K3s <a class="header-anchor" href="#install-k3s" aria-label="Permalink to &quot;Install K3s&quot;">​</a></h1><p>Deploy one <strong>k3s</strong> Kubernetes cluster across multiple cloud VMs using <strong>WireGuard</strong> tunnels managed by <strong>Netmaker</strong>.</p><h2 id="source" tabindex="-1">Source <a class="header-anchor" href="#source" aria-label="Permalink to &quot;Source&quot;">​</a></h2><ul><li><a href="https://itnext.io/how-to-deploy-a-single-kubernetes-cluster-across-multiple-clouds-using-k3s-and-wireguard-a5ae176a6e81" target="_blank" rel="noreferrer">ITNEXT: k3s + WireGuard + Netmaker</a> (Alex Feiszli, May 2021)</li><li>Related tutorial in this repo: <a href="./../README.html">Setting up k3s in LXC containers using Netmaker</a></li></ul><h2 id="why-this-pattern" tabindex="-1">Why this pattern <a class="header-anchor" href="#why-this-pattern" aria-label="Permalink to &quot;Why this pattern&quot;">​</a></h2><ul><li><strong>k3s</strong> uses SQL instead of etcd — tolerates higher-latency links between nodes</li><li><strong>WireGuard</strong> encrypts node-to-node traffic across public clouds</li><li><strong>Netmaker</strong> automates WireGuard peer config when nodes join/leave</li></ul><h2 id="architecture-demo" tabindex="-1">Architecture (demo) <a class="header-anchor" href="#architecture-demo" aria-label="Permalink to &quot;Architecture (demo)&quot;">​</a></h2><ul><li>Several Ubuntu 20.04 VMs with public IPs (e.g. Linode + AWS + home lab)</li><li>One VM runs Netmaker (Docker); others join a virtual subnet (e.g. <code>10.11.11.0/24</code>)</li><li>k3s server binds to the Netmaker interface (<code>nm-k3s</code>); agents join with the node token</li></ul><h2 id="part-1-—-netmaker" tabindex="-1">Part 1 — Netmaker <a class="header-anchor" href="#part-1-—-netmaker" aria-label="Permalink to &quot;Part 1 — Netmaker&quot;">​</a></h2><p>On the Netmaker VM (ports 80, 8081, 50051 open):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">wget</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -O</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docker-compose.yml</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/gravitl/netmaker/master/docker-compose.nodns.yml</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Set your VM IP in docker-compose.yml</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docker-compose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> up</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span></span></code></pre></div><p>Create network <code>k3s</code> / <code>10.11.11.0/24</code>, generate access key, run the install script on each cluster node (after <code>apt install wireguard-tools</code>).</p><h2 id="part-2-—-k3s-server" tabindex="-1">Part 2 — k3s server <a class="header-anchor" href="#part-2-—-k3s-server" aria-label="Permalink to &quot;Part 2 — k3s server&quot;">​</a></h2><p>On the master (replace IPs with your Netmaker addresses):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sfL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://get.k3s.io</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> INSTALL_K3S_EXEC</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;server --node-ip 10.11.11.1 --node-external-ip 10.11.11.1 --flannel-iface nm-k3s&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> -</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /var/lib/rancher/k3s/server/node-token</span></span></code></pre></div><h2 id="part-3-—-k3s-agents" tabindex="-1">Part 3 — k3s agents <a class="header-anchor" href="#part-3-—-k3s-agents" aria-label="Permalink to &quot;Part 3 — k3s agents&quot;">​</a></h2><p>On workers:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sfL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://get.k3s.io</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> INSTALL_K3S_EXEC</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;agent --server https://10.11.11.MASTER:6443 --token &lt;TOKEN&gt; --node-ip 10.11.11.X --node-external-ip 10.11.11.X --flannel-iface nm-k3s&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> -</span></span></code></pre></div><p>Verify with <code>kubectl get nodes</code> and cross-cloud pod ping tests (see article).</p><blockquote><p>Demo setup only — not production HA. See the article for ingress, storage, and HA follow-ups.</p></blockquote>`,20)])])}const u=e(n,[["render",r]]);export{c as __pageData,u as default};
